package org.apache.commons.csv;

import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.times;
import static org.mockito.Mockito.doThrow;

import java.io.Closeable;
import java.io.IOException;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterCloseTest {

    private Closeable closeableOut;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() throws Exception {
        closeableOut = mock(Closeable.class);
        CSVFormat format = mock(CSVFormat.class);

        // Use reflection to create CSVPrinter with a Closeable that is also Appendable
        // Create a proxy Appendable that delegates to closeableOut and implements Appendable
        Appendable appendableOut = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) {
                return this;
            }
            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                return this;
            }
            @Override
            public Appendable append(char c) {
                return this;
            }
            public void close() throws IOException {
                closeableOut.close();
            }
        };

        // Because CSVPrinter constructor requires Appendable, but we want closeableOut to be Closeable,
        // we create a dynamic proxy that implements both Appendable and Closeable.
        // But for simplicity, just cast closeableOut to Appendable will not work, so we use the above appendableOut.

        // However, the above appendableOut does not implement Closeable, so CSVPrinter.close() will not call closeableOut.close().
        // To fix that, we create a dynamic proxy implementing both Appendable and Closeable.

        Object proxy = java.lang.reflect.Proxy.newProxyInstance(
                Appendable.class.getClassLoader(),
                new Class<?>[]{Appendable.class, Closeable.class},
                (proxyObj, method, args) -> {
                    if ("close".equals(method.getName())) {
                        closeableOut.close();
                        return null;
                    }
                    if ("append".equals(method.getName())) {
                        // just return proxy itself for append methods
                        return proxyObj;
                    }
                    if ("toString".equals(method.getName())) {
                        return proxyObj.getClass().getName() + "@" + Integer.toHexString(proxyObj.hashCode());
                    }
                    return null;
                });

        // Now create CSVPrinter with the proxy as Appendable (and Closeable)
        Constructor<CSVPrinter> constructor = CSVPrinter.class.getConstructor(Appendable.class, CSVFormat.class);
        printer = constructor.newInstance(proxy, format);
    }

    @Test
    void testClose_whenOutIsCloseable_closesOut() throws IOException {
        printer.close();
        verify(closeableOut, times(1)).close();
    }

    @Test
    void testClose_whenOutIsCloseable_throwsIOException() throws IOException {
        doThrow(new IOException("close failed")).when(closeableOut).close();
        try {
            printer.close();
        } catch (IOException e) {
            // expected
        }
        verify(closeableOut, times(1)).close();
    }

    @Test
    void testClose_whenOutIsNotCloseable_doesNotThrow() throws IOException {
        Appendable nonCloseableOut = mock(Appendable.class);
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter nonCloseablePrinter = new CSVPrinter(nonCloseableOut, format);
        nonCloseablePrinter.close();
    }
}
